import React, { useState, useEffect } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useNavigate, useLocation } from 'react-router-dom';
import { MESSAGES } from '../../utils/constants';
import Alert from '../common/Alert';
import Modal from '../common/Modal';
import Button from '../common/Button';
import CurrencyManager from './CurrencyManager';
import PendingApprovals from './PendingApprovals';
import VideoManager from './VideoManager';
import DashboardStats from './DashboardStats';
import UserManagement from './UserManagement';
import ProfileManager from './ProfileManager';
import { currencyService } from '../../services/currencyService';
import './AdminPanel.css';

// Rate History Component (keep existing)
const RateHistory = () => {
    // ... existing code
};

// Settings Component (keep existing)
const Settings = () => {
    // ... existing code
};

// Main AdminPanel Component
const AdminPanel = () => {
    const location = useLocation();
    const [activeTab, setActiveTab] = useState('dashboard');
    const [sidebarOpen, setSidebarOpen] = useState(true);
    const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
    const { user, logout, success, error, setError } = useAuth();
    const navigate = useNavigate();

    useEffect(() => {
        const params = new URLSearchParams(location.search);
        const tab = params.get('tab');
        if (tab) {
            setActiveTab(tab);
        }
    }, [location]);

    const handleLogout = () => {
        setShowLogoutConfirm(false);
        logout();
        setTimeout(() => {
            navigate('/admin/login');
        }, 500);
    };

    const toggleSidebar = () => {
        setSidebarOpen(!sidebarOpen);
    };

    const menuItems = [
        { id: 'dashboard', label: 'Dashboard', icon: 'fa-tachometer-alt' },
        { id: 'currencies', label: 'Currency Manager', icon: 'fa-coins' },
        { id: 'pending', label: 'Pending Approvals', icon: 'fa-clock' },
        { id: 'videos', label: 'Video Manager', icon: 'fa-video' },
        { id: 'users', label: 'User Management', icon: 'fa-users' },
        { id: 'profile', label: 'My Profile', icon: 'fa-user-circle' },
        { id: 'reports', label: 'Rate History', icon: 'fa-chart-line' },
        { id: 'settings', label: 'Settings', icon: 'fa-cog' }
    ];

    const renderContent = () => {
        switch(activeTab) {
            case 'dashboard':
                return <DashboardStats />;
            case 'currencies':
                return <CurrencyManager />;
            case 'pending':
                return <PendingApprovals />;
            case 'videos':
                return <VideoManager />;
            case 'users':
                return <UserManagement />;
            case 'profile':
                return <ProfileManager />;
            case 'reports':
                return <RateHistory />;
            case 'settings':
                return <Settings />;
            default:
                return <DashboardStats />;
        }
    };

    const currentYear = new Date().getFullYear();

    return (
        <div className="admin-panel-advanced">
            {/* Success Message */}
            {success && (
                <div className="toast-message success">
                    <i className="fas fa-check-circle"></i>
                    <span>{success}</span>
                    <button onClick={() => window.location.reload()} className="toast-close">
                        <i className="fas fa-times"></i>
                    </button>
                </div>
            )}
            
            {/* Error Message */}
            {error && (
                <div className="toast-message error">
                    <i className="fas fa-exclamation-circle"></i>
                    <span>{error}</span>
                    <button onClick={() => setError(null)} className="toast-close">
                        <i className="fas fa-times"></i>
                    </button>
                </div>
            )}

            {/* Logout Confirmation Modal */}
            <Modal
                isOpen={showLogoutConfirm}
                onClose={() => setShowLogoutConfirm(false)}
                title={{ text: 'Confirm Logout', icon: 'question-circle' }}
                size="sm"
                footer={
                    <>
                        <Button variant="danger" onClick={handleLogout}>
                            Logout
                        </Button>
                        <Button variant="secondary" onClick={() => setShowLogoutConfirm(false)}>
                            Cancel
                        </Button>
                    </>
                }
            >
                <p>{MESSAGES.CONFIRM_LOGOUT}</p>
            </Modal>

            {/* Top Navigation Bar */}
            <div className="admin-top-bar">
                <button className="menu-toggle" onClick={toggleSidebar}>
                    <i className={`fas ${sidebarOpen ? 'fa-times' : 'fa-bars'}`}></i>
                </button>
                <div className="admin-logo">
                    <i className="fas fa-landmark"></i>
                    <div className="logo-text">
                        <span>DASHEN BANK</span>
                        <small>Exchange Rate Management System</small>
                    </div>
                </div>
                <div className="top-nav">
                    <div className="date-time">
                        <i className="far fa-calendar-alt"></i>
                        <span>{new Date().toLocaleDateString('en-US', { weekday: 'short', month: 'short', day: 'numeric', year: 'numeric' })}</span>
                    </div>
                    <div className="notifications">
                        <i className="fas fa-bell"></i>
                        <span className="badge">0</span>
                    </div>
                    <div className="user-menu">
                        <div className="user-avatar">
                            <i className="fas fa-user-circle"></i>
                        </div>
                        <div className="user-info">
                            <span className="user-name">{user?.username || 'Admin'}</span>
                            <span className="user-role">{user?.role === 'super_admin' ? 'Super Administrator' : 'Administrator'}</span>
                        </div>
                        <button onClick={() => setShowLogoutConfirm(true)} className="logout-btn">
                            <i className="fas fa-sign-out-alt"></i>
                            <span>Logout</span>
                        </button>
                    </div>
                </div>
            </div>

            {/* Sidebar & Main Content */}
            <div className="admin-layout">
                <aside className={`admin-sidebar ${sidebarOpen ? 'open' : 'closed'}`}>
                    <div className="sidebar-header">
                        <i className="fas fa-chart-line"></i>
                        <span>Exchange Manager</span>
                    </div>
                    <nav className="sidebar-nav">
                        {menuItems.map(item => (
                            <button
                                key={item.id}
                                className={`nav-item ${activeTab === item.id ? 'active' : ''}`}
                                onClick={() => setActiveTab(item.id)}
                            >
                                <i className={`fas ${item.icon}`}></i>
                                <span>{item.label}</span>
                            </button>
                        ))}
                    </nav>
                    <div className="sidebar-footer">
                        <div className="system-status">
                            <i className="fas fa-circle"></i>
                            <span>System Online</span>
                        </div>
                        <div className="version">
                            <i className="fas fa-code-branch"></i>
                            v2.0.0
                        </div>
                    </div>
                </aside>

                <main className={`admin-main ${sidebarOpen ? 'sidebar-open' : 'sidebar-closed'}`}>
                    <div className="page-header">
                        <h1>
                            <i className={`fas ${menuItems.find(m => m.id === activeTab)?.icon || 'fa-dashboard'}`}></i>
                            {menuItems.find(m => m.id === activeTab)?.label || 'Dashboard'}
                        </h1>
                        <div className="breadcrumb">
                            <span>Home</span>
                            <i className="fas fa-chevron-right"></i>
                            <span>{menuItems.find(m => m.id === activeTab)?.label || 'Dashboard'}</span>
                        </div>
                    </div>
                    <div className="page-content">
                        {renderContent()}
                    </div>

                    {/* Footer */}
                    <footer className="admin-footer">
                        <div className="footer-content">
                            <div className="footer-copyright">
                                <i className="fas fa-copyright"></i>
                                <span>{currentYear} - {currentYear} Dashen Bank SC | All Rights Reserved</span>
                            </div>
                            <div className="footer-developer-wrapper">
                                <div className="footer-developer">
                                    <i className="fas fa-code"></i>
                                    <span>Developed by : Seid Mohammed</span>
                                </div>
                                <div className="developer-photo-tooltip">
                                    <img 
                                        src="/developer.jpg" 
                                        alt="Seid Mohammed - Developer"
                                        className="developer-photo"
                                        onError={(e) => {
                                            e.target.onerror = null;
                                            e.target.src = "https://via.placeholder.com/250x150/003366/white?text=SM";
                                        }}
                                    />
                                    <div className="tooltip-info">
                                        <h4>Seid Mohammed</h4>
                                        <p>Senior Software Engineer</p>
                                        <div className="developer-bio">
                                            Passionate developer creating innovative business solutions for Dashen Bank
                                        </div>
                                        <div className="social-links">
                                            <a href="#" target="_blank" rel="noopener noreferrer" title="GitHub">
                                                <i className="fab fa-github"></i>
                                            </a>
                                            <a href="#" target="_blank" rel="noopener noreferrer" title="LinkedIn">
                                                <i className="fab fa-linkedin"></i>
                                            </a>
                                            <a href="#" target="_blank" rel="noopener noreferrer" title="Twitter">
                                                <i className="fab fa-twitter"></i>
                                            </a>
                                            <a href="mailto:seid@dashenbank.com" title="Email">
                                                <i className="fas fa-envelope"></i>
                                            </a>
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </footer>
                </main>
            </div>
        </div>
    );
};

export default AdminPanel;
